String index_page="<!DOCTYPE html>\n<html lang=\"it\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>Device Info</title>\n  <style>\n* {\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n}\nbody {\n  height: 100vh;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: #f4f4f4;\n  font-family: Arial, sans-serif;\n  color: #222;\n}\n.card {\n  background: white;\n  padding: 32px;\n  border-radius: 16px;\n  box-shadow: 0 4px 20px rgba(0,0,0,0.08);\n  min-width: 320px;\n  text-align: center;\n}\n.title {\n  font-size: 22px;\n  margin-bottom: 24px;\n  font-weight: bold;\n}\n.row {\n  margin: 10px 0;\n}\n.label {\n  font-size: 12px;\n  color: #777;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n}\n.value {\n  font-size: 16px;\n  margin-top: 4px;\n  word-break: break-word;\n}\n  </style>\n</head>\n<body>\n  <div class=\"card\">\n<div class=\"title\">Info Dispositivo</div>\n<div class=\"row\">\n  <div class=\"label\">SSID</div>\n  <div class=\"value\" id=\"ssid\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">MAC</div>\n  <div class=\"value\" id=\"mac\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">RSSI</div>\n  <div class=\"value\" id=\"rssi\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">mDNS</div>\n  <div class=\"value\" id=\"mdns\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">DDNS</div>\n  <div class=\"value\" id=\"ddns\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">DDNS IP</div>\n  <div class=\"value\" id=\"ddns_ip\">-</div>\n</div>\n<div class=\"row\">\n  <div class=\"label\">Public IP</div>\n  <div class=\"value\" id=\"public_ip\">-</div>\n</div>\n  </div>\n  <script>\nasync function loadInfo() {\n  try {\nconst res = await fetch(\'/api/info\');\nconst data = await res.json();\nObject.keys(data).forEach(key => {\n  const el = document.getElementById(key);\n  if (el) {\nel.textContent = data[key];\n  }\n});\n  } catch (err) {\nconsole.error(err);\n  }\n}\nloadInfo();\n  </script>\n</body>\n</html>\n";